import"./ticker-BxUDbM2L.js";import{i as a}from"./country-page-CK6BdUjw.js";import"./utils-Owvk3OYq.js";import"./breadcrumbs-CxxVGuAV.js";a({countryCode:"SA",currency:"SAR",flag:"🇸🇦",nameEn:"Saudi Arabia",nameAr:"المملكة العربية السعودية",fixedPeg:!1,decimals:2,timezone:"Asia/Riyadh",relatedCountries:[{file:"uae.html",nameEn:"UAE",nameAr:"الإمارات",flag:"🇦🇪"},{file:"kuwait.html",nameEn:"Kuwait",nameAr:"الكويت",flag:"🇰🇼"},{file:"qatar.html",nameEn:"Qatar",nameAr:"قطر",flag:"🇶🇦"},{file:"bahrain.html",nameEn:"Bahrain",nameAr:"البحرين",flag:"🇧🇭"},{file:"oman.html",nameEn:"Oman",nameAr:"عُمان",flag:"🇴🇲"},{file:"egypt.html",nameEn:"Egypt",nameAr:"مصر",flag:"🇪🇬"}],faqEn:[{q:"What is today's gold price in Saudi Arabia (SAR per gram)?",a:"The live gold price in Saudi Arabia is calculated from the global XAU/USD spot rate, converted to SAR using the current USD/SAR exchange rate. The Saudi Riyal is loosely pegged near 3.75 SAR per USD, so prices are highly stable. Check the price card above for the current rate."},{q:"What karat of gold is most popular in Saudi Arabia?",a:"21K gold is very popular in Saudi Arabia for traditional jewellery and bridal sets. 22K and 24K are also widely available, with 24K preferred for investment coins and bars."},{q:"Where can I buy gold in Saudi Arabia?",a:"Gold is widely sold in jewellery souks across major cities including Riyadh, Jeddah, and Makkah. The gold souks in these cities are known for competitive prices and wide variety. Banks and investment companies also sell certified gold bars and coins."},{q:"Is there VAT on gold in Saudi Arabia?",a:"Saudi Arabia introduced a 15% VAT in 2020. Investment-grade gold (bars and coins meeting purity standards) is VAT-exempt. Jewellery and other gold products are subject to the 15% VAT rate, which significantly affects retail gold prices."},{q:"How is the Saudi Riyal exchange rate determined?",a:"The Saudi Riyal is managed within a narrow band around 3.75 SAR/USD by the Saudi Arabian Monetary Authority (SAMA). While not an official fixed peg like the UAE Dirham, the SAR is extremely stable against the Dollar, making gold price forecasting reliable."}],faqAr:[{q:"ما هو سعر الذهب اليوم في السعودية (ريال للغرام)؟",a:"يتم احتساب سعر الذهب في السعودية من سعر XAU/USD العالمي، محولاً إلى ريال سعودي بسعر الصرف الحالي. الريال السعودي مرتبط فعلياً بحوالي 3.75 ريال للدولار، لذا فالأسعار مستقرة جداً. تحقق من بطاقة السعر أعلاه للحصول على السعر الحالي."},{q:"ما هو العيار الأكثر شيوعاً في السعودية؟",a:"يُعد عيار 21 شائعاً جداً في السعودية للمجوهرات التقليدية وطقم العرائس. تتوفر أيضاً عيارات 22 و24، ويُفضَّل عيار 24 للعملات والسبائك الاستثمارية."},{q:"أين يمكن شراء الذهب في السعودية؟",a:"يُباع الذهب على نطاق واسع في أسواق المجوهرات في المدن الكبرى كالرياض وجدة ومكة المكرمة. تُعرف أسواق الذهب في هذه المدن بأسعارها التنافسية وتنوعها الواسع. تبيع البنوك وشركات الاستثمار أيضاً سبائك وعملات ذهبية معتمدة."},{q:"هل يوجد ضريبة قيمة مضافة على الذهب في السعودية؟",a:"أدخلت السعودية ضريبة القيمة المضافة بنسبة 15% عام 2020. يُعفى الذهب الاستثماري (السبائك والعملات التي تستوفي معايير النقاء) من هذه الضريبة، بينما تخضع المجوهرات ومنتجات الذهب الأخرى لمعدل 15%."},{q:"كيف يُحدَّد سعر صرف الريال السعودي؟",a:"تُدير مؤسسة النقد العربي السعودي (ساما) الريال ضمن نطاق ضيق حول 3.75 ريال/دولار. رغم أنه ليس ربطاً رسمياً ثابتاً كالدرهم الإماراتي، إلا أن الريال مستقر جداً مقابل الدولار."}]});
